const html = $input.first().json.data;

const rowRegex = /<tr[\s\S]*?<\/tr>/gi;
const stripTags = s => s.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

const v12 = [];
const v13 = [];

let rowMatch;
while ((rowMatch = rowRegex.exec(html)) !== null) {
  const cells = [];
  const cellRe = /<td[\s\S]*?>(.*?)<\/td>/gi;
  let cellMatch;
  while ((cellMatch = cellRe.exec(rowMatch[0])) !== null) {
    cells.push(stripTags(cellMatch[1]));
  }
  if (cells.length >= 3 && /^\d+\.\d+\.\d+\.\d+$/.test(cells[1])) {
    const entry = { version: cells[0], build: cells[1], releaseDate: cells[2] };
    if (cells[1].startsWith('13.')) v13.push(entry);
    else if (cells[1].startsWith('12.')) v12.push(entry);
  }
}

const results = [...v13.slice(0, 3), ...v12.slice(0, 3)];
return results.map(r => ({ json: r }));
